//! CLI tool that diffs two session JSONL files and prints a colored summary.
//!
//! Usage:
//!   cargo run --example session_diff -- <old.jsonl> <new.jsonl>
//!
//! Output sections:
//!   - Session metadata changes
//!   - Compaction events
//!   - Removed messages (present in old, missing in new)
//!   - New messages (present in new, missing in old)
//!   - Token usage changes

use std::env;
use std::process;

use runtime::{
    ContentBlock, ConversationMessage, MessageRole, Session, SessionCompaction, TokenUsage,
    UsageTracker,
};

// ── ANSI helpers ────────────────────────────────────────────────────────────

const RED: &str = "\x1b[31m";
const GREEN: &str = "\x1b[32m";
const YELLOW: &str = "\x1b[33m";
const CYAN: &str = "\x1b[36m";
const BOLD: &str = "\x1b[1m";
const DIM: &str = "\x1b[2m";
const RESET: &str = "\x1b[0m";

// ── Display helpers ─────────────────────────────────────────────────────────

fn role_str(role: MessageRole) -> &'static str {
    match role {
        MessageRole::System => "system",
        MessageRole::User => "user",
        MessageRole::Assistant => "assistant",
        MessageRole::Tool => "tool",
    }
}

fn block_summary(block: &ContentBlock) -> String {
    match block {
        ContentBlock::Text { text } => {
            let preview = if text.len() > 80 {
                format!("{}...", &text[..80])
            } else {
                text.clone()
            };
            format!("Text({preview})")
        }
        ContentBlock::ToolUse { name, .. } => format!("ToolUse({name})"),
        ContentBlock::ToolResult {
            tool_name,
            is_error,
            ..
        } => {
            let err = if *is_error { ", ERROR" } else { "" };
            format!("ToolResult({tool_name}{err})")
        }
    }
}

fn print_message(prefix: &str, color: &str, idx: usize, msg: &ConversationMessage) {
    let blocks: Vec<String> = msg.blocks.iter().map(block_summary).collect();
    println!(
        "{color}{prefix} [{idx}] {:<10} {}{RESET}",
        role_str(msg.role),
        blocks.join(" | ")
    );
    if let Some(usage) = msg.usage {
        println!(
            "{color}{prefix}     tokens: in={} out={} cache_create={} cache_read={}{RESET}",
            usage.input_tokens,
            usage.output_tokens,
            usage.cache_creation_input_tokens,
            usage.cache_read_input_tokens,
        );
    }
}

// ── Compaction diff ─────────────────────────────────────────────────────────

fn diff_compaction(old: &Option<SessionCompaction>, new: &Option<SessionCompaction>) {
    println!("\n{BOLD}{CYAN}=== Compaction ==={RESET}");
    match (old, new) {
        (None, None) => println!("  {DIM}(no compaction in either session){RESET}"),
        (None, Some(c)) => {
            println!(
                "  {GREEN}+ compaction: count={}, removed={} msgs{RESET}",
                c.count, c.removed_message_count
            );
            println!("  {GREEN}+ summary: {}{RESET}", c.summary);
        }
        (Some(c), None) => {
            println!(
                "  {RED}- compaction: count={}, removed={} msgs{RESET}",
                c.count, c.removed_message_count
            );
            println!("  {RED}- summary: {}{RESET}", c.summary);
        }
        (Some(a), Some(b)) => {
            if a == b {
                println!(
                    "  {DIM}(unchanged) count={}, removed={} msgs{RESET}",
                    a.count, a.removed_message_count
                );
            } else {
                if a.count != b.count {
                    println!(
                        "  {YELLOW}~ count: {} -> {}{RESET}",
                        a.count, b.count
                    );
                }
                if a.removed_message_count != b.removed_message_count {
                    println!(
                        "  {YELLOW}~ removed_message_count: {} -> {}{RESET}",
                        a.removed_message_count, b.removed_message_count
                    );
                }
                if a.summary != b.summary {
                    println!("  {RED}- summary: {}{RESET}", a.summary);
                    println!("  {GREEN}+ summary: {}{RESET}", b.summary);
                }
            }
        }
    }
}

// ── Message diff ────────────────────────────────────────────────────────────

fn diff_messages(old: &[ConversationMessage], new: &[ConversationMessage]) {
    println!("\n{BOLD}{CYAN}=== Messages ==={RESET}");
    println!(
        "  old: {} message(s)  |  new: {} message(s)",
        old.len(),
        new.len()
    );

    let common = old.len().min(new.len());

    // Walk shared prefix — flag changed messages.
    let mut changed_count = 0usize;
    for i in 0..common {
        if old[i] != new[i] {
            changed_count += 1;
            println!();
            print_message("  -", RED, i, &old[i]);
            print_message("  +", GREEN, i, &new[i]);
        }
    }

    // Messages only in old (removed tail).
    if old.len() > common {
        println!(
            "\n{BOLD}{RED}--- Removed messages ({}) ---{RESET}",
            old.len() - common
        );
        for i in common..old.len() {
            print_message("  -", RED, i, &old[i]);
        }
    }

    // Messages only in new (added tail).
    if new.len() > common {
        println!(
            "\n{BOLD}{GREEN}+++ New messages ({}) +++{RESET}",
            new.len() - common
        );
        for i in common..new.len() {
            print_message("  +", GREEN, i, &new[i]);
        }
    }

    if changed_count == 0 && old.len() == new.len() {
        println!("  {DIM}(messages identical){RESET}");
    }
}

// ── Token usage diff ────────────────────────────────────────────────────────

fn aggregate_usage(session: &Session) -> TokenUsage {
    let tracker = UsageTracker::from_session(session);
    tracker.cumulative_usage()
}

fn diff_usage(old: &Session, new: &Session) {
    println!("\n{BOLD}{CYAN}=== Token Usage ==={RESET}");
    let old_u = aggregate_usage(old);
    let new_u = aggregate_usage(new);

    let fields: &[(&str, u32, u32)] = &[
        ("input_tokens", old_u.input_tokens, new_u.input_tokens),
        ("output_tokens", old_u.output_tokens, new_u.output_tokens),
        (
            "cache_creation",
            old_u.cache_creation_input_tokens,
            new_u.cache_creation_input_tokens,
        ),
        (
            "cache_read",
            old_u.cache_read_input_tokens,
            new_u.cache_read_input_tokens,
        ),
    ];

    for (name, a, b) in fields {
        if a == b {
            println!("  {DIM}{name:<20} {a}{RESET}");
        } else {
            let delta = i64::from(*b) - i64::from(*a);
            let sign = if delta > 0 { "+" } else { "" };
            let color = if delta > 0 { RED } else { GREEN };
            println!("  {color}{name:<20} {a} -> {b}  ({sign}{delta}){RESET}");
        }
    }
}

// ── Metadata diff ───────────────────────────────────────────────────────────

fn diff_metadata(old: &Session, new: &Session) {
    println!("{BOLD}{CYAN}=== Session Metadata ==={RESET}");
    if old.session_id != new.session_id {
        println!(
            "  {YELLOW}session_id: {} -> {}{RESET}",
            old.session_id, new.session_id
        );
    } else {
        println!("  {DIM}session_id: {}{RESET}", old.session_id);
    }
    if old.version != new.version {
        println!(
            "  {YELLOW}version: {} -> {}{RESET}",
            old.version, new.version
        );
    }
    if old.created_at_ms != new.created_at_ms {
        println!(
            "  {YELLOW}created_at_ms: {} -> {}{RESET}",
            old.created_at_ms, new.created_at_ms
        );
    }
    if old.fork != new.fork {
        println!("  {YELLOW}fork metadata changed{RESET}");
    }
}

// ── main ────────────────────────────────────────────────────────────────────

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() != 3 {
        eprintln!("Usage: session_diff <old.jsonl> <new.jsonl>");
        process::exit(1);
    }

    let old = Session::load_from_path(&args[1]).unwrap_or_else(|e| {
        eprintln!("Error loading {}: {e}", args[1]);
        process::exit(1);
    });
    let new = Session::load_from_path(&args[2]).unwrap_or_else(|e| {
        eprintln!("Error loading {}: {e}", args[2]);
        process::exit(1);
    });

    diff_metadata(&old, &new);
    diff_compaction(&old.compaction, &new.compaction);
    diff_messages(&old.messages, &new.messages);
    diff_usage(&old, &new);

    println!();
}

tools.description:
Creates a new field in an existing Airtable table.
To get baseId and tableId, use the search_bases and list_tables_for_base tools first.
Example: create a singleSelect "Status" field:
{"baseId": "appZfrNIUEip5MazD", "tableId": "tblGlReoTNWfYnXIG", "field": {"name": "Status", "type": "singleSelect", "options": {"choices": [{"name": "Todo"}, {"name": "In progress"}, {"name": "Done"}]}}}
Example: create a number "Priority" field:
{"baseId": "appZfrNIUEip5MazD", "tableId": "tblGlReoTNWfYnXIG", "field": {"name": "Priority", "type": "number", "options": {"precision": 0}}}

filters.description:
Describes the filters to apply to the records using a structured format.
Example filter where the value of the field with ID "fld8WsrpLHHevsnW8" is "orange" or the value of the field with ID "fldulcCPDVz87Bmnw" is greater than 5:
{"operator": "or", "operands": [{"operator": "=", "operands": ["fld8WsrpLHHevsnW8", "orange"]}, {"operator": ">", "operands": ["fldulcCPDVz87Bmnw", 5]}]}
Example filter where the value of the collaborator field with ID "fldCRi9oz2vRLcIWr" can be any user in a group with ID "ugpDUVUnftA7H9bG8" and the value of the field with ID "fldgD18XtsueoiguT" equals select option with ID "selha8nGNAT5ATR7P":
{"operator": "and", "operands": [{"operator": "hasAnyOf", "operands": ["fldCRi9oz2vRLcIWr", "ugpDUVUnftA7H9bG8"], "operatorOptions": {"matchGroupsByMembership": true}}, {"operator": "=", "operands": ["fldgD18XtsueoiguT", "selha8nGNAT5ATR7P"]}]}
Example filter for records where a date field is within the past week:
{"operands": [{"operator": "isWithin", "operands": ["fldABC12345678x", {"mode": "pastWeek", "timeZone": "America/New_York"}]}]}
Example filter for records where a field is not empty:
{"operands": [{"operator": "isNotEmpty", "operands": ["fldABC12345678x"]}]}
